Ok, I found a way to trigger the problem with this silly perl script on the Linux client, so no need to pull off a complete GCC bootstrap:

#!/usr/bin/perl

use strict;
use warnings;

use threads;
use IO::Handle;
use Fcntl qw(SEEK_SET SEEK_CUR SEEK_END);

my $testfile = 'testfile';

my $thread = {};
map { $thread->{$_} = threads->create(
    sub {
        open(my $fh, '+>', $testfile) or die "Can't open +> $testfile: $!";
        my $id = $_;
        map {
            seek $fh, int(rand(1024*4096)), SEEK_SET;
            print $fh 'foobar' x (500 + int(rand(4000)));
            $fh->flush();
        } (0..10000);
        close $fh;
    }
) } (0..1000);

map {
    $thread->{$_}->join();
} (0..1000);
